import os
import subprocess

def backup_directory(directory_path, format):
    if not os.path.exists(directory_path):
        print(f"Error: Directory '{directory_path}' does not exist.")
        return
    
    if format.lower() == 'tar.gz':
        command = ['tar', '-czf', f'{os.path.basename(directory_path)}.tgz', directory_path]
    elif format.lower() == 'tar.bz2':
        command = ['tar', '-cjf', f'{os.path.basename(directory_path)}.tbz2', directory_path]
    elif format.lower() == 'zip':
        command = ['zip', f'{os.path.basename(directory_path)}.zip', directory_path]
    elif format.lower() == '7z':
        command = ['7z', 'a', f'{os.path.basename(directory_path)}.7z', directory_path]
    else:
        print(f"Error: Unsupported compression format '{format}'.")
        return
    
    try:
        subprocess.run(command, check=True)
        print(f"Backup of '{directory_path}' created successfully in {format} format.")
    except subprocess.CalledProcessError as e:
        print(f"Error creating backup: {e}")

if __name__ == "__main__":
    import argparse
    parser = argparse.ArgumentParser(description='Create compressed backups of user directories.')
    parser.add_argument('directory', help='Path to the directory to be backed up')
    parser.add_argument('-f', '--format', default='tar.gz', choices=['tar.gz', 'tar.bz2', 'zip', '7z'], help='Compression format (default: tar.gz)')
    args = parser.parse_args()
    
    backup_directory(args.directory, args.format)